@import '../../utils/focus-ring.css';
@import '../../utils/control-inactive.css';

:host {
  box-sizing: border-box;
  display: block;
  width: 100%;
  --_swatch-inner-inset: calc(
    var(--dimension-stroke-width-025) + var(--dimension-space-025)
  );
  --_swatch-ring-bg: var(--color-background-primary);
  --_swatch-select-motion: var(--effect-motion-short-3);
}

.swatch-picker {
  box-sizing: border-box;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  width: 100%;
  min-height: var(--dimension-size-400);
  gap: var(--dimension-space-100);
  padding: var(--dimension-space-100);
}

.swatch-picker__option {
  position: relative;
  box-sizing: border-box;
  flex: 0 0 auto;
  width: var(--dimension-size-300);
  height: var(--dimension-size-300);
  padding: 0;
  border: none;
  border-radius: var(--dimension-radius-half);
  background: transparent;
  cursor: pointer;
  isolation: isolate;
}

.swatch-picker__fill,
.swatch-picker__border,
.swatch-picker__interaction,
.swatch-picker__halo,
.swatch-picker__stroke {
  position: absolute;
  inset: 0;
  border-radius: inherit;
  pointer-events: none;
}

.swatch-picker__fill {
  z-index: 1;
  background-color: var(--_swatch-preview-color);
  background-image: var(--_swatch-preview-image);
  background-repeat: no-repeat;
  background-position: center;
  background-size: cover;
  opacity: var(--_swatch-preview-opacity);
  transition:
    inset var(--_swatch-select-motion);
}

.swatch-picker__border {
  z-index: 2;
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-012) var(--color-border-secondary);
  transition:
    inset var(--_swatch-select-motion);
}

.swatch-picker__interaction {
  z-index: 3;
  background-color: transparent;
  transition:
    inset var(--_swatch-select-motion),
    background-color 0s;
}

.swatch-picker__option:hover:not(:disabled) .swatch-picker__interaction {
  background-color: var(--color-interaction-hover);
}

.swatch-picker__option:active:not(:disabled) .swatch-picker__interaction {
  background-color: var(--color-interaction-pressed);
}

.swatch-picker__halo,
.swatch-picker__stroke {
  opacity: 0;
  transform: scale(1.2);
  transform-origin: center;
  transition:
    opacity var(--_swatch-select-motion),
    transform var(--_swatch-select-motion);
}

.swatch-picker__halo {
  z-index: 4;
  box-shadow: inset 0 0 0 var(--_swatch-inner-inset) var(--_swatch-ring-bg);
}

.swatch-picker__stroke {
  z-index: 5;
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-025) var(--color-border-bold-brand);
}

.swatch-picker__option--selected .swatch-picker__fill,
.swatch-picker__option--selected .swatch-picker__border,
.swatch-picker__option--selected .swatch-picker__interaction {
  inset: var(--_swatch-inner-inset);
}

.swatch-picker__option--selected .swatch-picker__halo,
.swatch-picker__option--selected .swatch-picker__stroke {
  opacity: 1;
  transform: scale(1);
}

.swatch-picker__divider {
  flex: 0 0 auto;
  align-self: center;
  width: var(--dimension-stroke-width-012);
  height: var(--dimension-size-300);
  background-color: var(--color-border-tertiary);
}

@media (prefers-reduced-motion: reduce) {
  .swatch-picker__fill,
  .swatch-picker__border,
  .swatch-picker__interaction,
  .swatch-picker__halo,
  .swatch-picker__stroke {
    transition: none;
  }
}

import { Component, Element, Event, EventEmitter, Prop, h, Host } from '@stencil/core';
import {
  flattenSwatchPickerOptions,
  normalizeSwatchPickerOpacity,
  resolveSwatchPickerNavigationIndex,
  resolveSwatchPickerTabIndex,
  type SwatchPickerNavigationKey,
  type SwatchPickerOption,
  type SwatchPickerSection,
} from './swatch-picker-types';

@Component({
  tag: 'ds-swatch-picker',
  styleUrl: 'SwatchPicker.css',
  scoped: true,
})
export class SwatchPicker {
  @Element() el!: HTMLElement;

  /** Selected option value. */
  @Prop({ mutable: true, reflect: true }) value: string = '';

  /** Flat option list. Sections take precedence when supplied. Assign as a JavaScript property. */
  @Prop() options: SwatchPickerOption[] = [];

  /** Visually separated option groups that remain one radio group. Assign as a JavaScript property. */
  @Prop() sections: SwatchPickerSection[] = [];

  /** Accessible name for the complete one-of-many choice. */
  @Prop() groupLabel: string = 'Swatch options';

  @Event() dsChange!: EventEmitter<string>;

  private get activeOptions(): SwatchPickerOption[] {
    return flattenSwatchPickerOptions(this.options, this.sections);
  }

  private selectOption(option: SwatchPickerOption) {
    if (option.isInactive || option.value === this.value) return;
    this.value = option.value;
    this.dsChange.emit(option.value);
  }

  private focusOption(index: number) {
    requestAnimationFrame(() => {
      const optionButtons = this.el
        .querySelectorAll<HTMLButtonElement>('.swatch-picker__option');
      optionButtons[index]?.focus();
    });
  }

  private handleOptionKeyDown(
    event: KeyboardEvent,
    currentIndex: number,
  ) {
    const key = event.key as SwatchPickerNavigationKey;
    if (!['ArrowDown', 'ArrowLeft', 'ArrowRight', 'ArrowUp', 'Home', 'End'].includes(key)) {
      return;
    }

    const nextIndex = resolveSwatchPickerNavigationIndex(
      this.activeOptions,
      currentIndex,
      key,
    );
    if (nextIndex === null) return;

    event.preventDefault();
    const nextOption = this.activeOptions[nextIndex];
    this.selectOption(nextOption);
    this.focusOption(nextIndex);
  }

  private renderOption(
    option: SwatchPickerOption,
    index: number,
    tabIndex: number,
  ) {
    const selected = option.value === this.value;
    const opacity = normalizeSwatchPickerOpacity(option.preview.opacity);

    return (
      <button
        key={option.value}
        type="button"
        class={{
          'swatch-picker__option': true,
          'swatch-picker__option--selected': selected,
          'ds-focus-ring-inset': true,
          'ds-control-inactive': !!option.isInactive,
        }}
        style={{
          '--_swatch-preview-color': option.preview.backgroundColor ?? 'var(--color-background-secondary)',
          '--_swatch-preview-image': option.preview.backgroundImage ?? 'none',
          '--_swatch-preview-opacity': String(opacity),
        }}
        role="radio"
        aria-label={option.label}
        aria-checked={selected ? 'true' : 'false'}
        tabIndex={index === tabIndex ? 0 : -1}
        disabled={option.isInactive}
        onClick={() => this.selectOption(option)}
        onKeyDown={(event: KeyboardEvent) => this.handleOptionKeyDown(event, index)}
      >
        <span class="swatch-picker__fill" aria-hidden="true" />
        <span class="swatch-picker__border" aria-hidden="true" />
        <span class="swatch-picker__interaction" aria-hidden="true" />
        <span class="swatch-picker__halo" aria-hidden="true" />
        <span class="swatch-picker__stroke" aria-hidden="true" />
      </button>
    );
  }

  render() {
    const activeOptions = this.activeOptions;
    const tabIndex = resolveSwatchPickerTabIndex(activeOptions, this.value);
    let optionIndex = 0;

    return (
      <Host>
        <div
          class="swatch-picker"
          role="radiogroup"
          aria-label={this.groupLabel}
        >
          {(this.sections.length > 0 ? this.sections : [{ options: this.options }]).map((section, sectionIndex) => [
            section.options.map(option => {
              const currentIndex = optionIndex++;
              return this.renderOption(option, currentIndex, tabIndex);
            }),
            sectionIndex < (this.sections.length > 0 ? this.sections.length : 1) - 1 && (
              <span class="swatch-picker__divider" aria-hidden="true" />
            ),
          ])}
        </div>
      </Host>
    );
  }
}

export interface SwatchPickerPreview {
  /** CSS color used as the swatch base or as a complete flat-color preview. */
  backgroundColor?: string;
  /** CSS gradient used as the swatch image. */
  backgroundImage?: string;
  /** Optional preview-layer opacity, clamped to the inclusive 0–1 range. */
  opacity?: number;
}

export interface SwatchPickerOption {
  /** Stable value emitted when this option is selected. */
  value: string;
  /** Accessible option name; the visual preview never replaces this label. */
  label: string;
  preview: SwatchPickerPreview;
  isInactive?: boolean;
}

export interface SwatchPickerSection {
  /** Sections remain one radio group and are separated visually. */
  options: SwatchPickerOption[];
}

export type SwatchPickerNavigationKey =
  | 'ArrowDown'
  | 'ArrowLeft'
  | 'ArrowRight'
  | 'ArrowUp'
  | 'Home'
  | 'End';

export function flattenSwatchPickerOptions(
  options: readonly SwatchPickerOption[],
  sections: readonly SwatchPickerSection[],
): SwatchPickerOption[] {
  return sections.length > 0
    ? sections.flatMap(section => section.options)
    : [...options];
}

export function resolveSwatchPickerTabIndex(
  options: readonly SwatchPickerOption[],
  value: string,
): number {
  const selectedIndex = options.findIndex(option => (
    option.value === value && !option.isInactive
  ));
  if (selectedIndex >= 0) return selectedIndex;
  return options.findIndex(option => !option.isInactive);
}

export function resolveSwatchPickerNavigationIndex(
  options: readonly SwatchPickerOption[],
  currentIndex: number,
  key: SwatchPickerNavigationKey,
): number | null {
  const enabledIndexes = options
    .map((option, index) => ({ option, index }))
    .filter(({ option }) => !option.isInactive)
    .map(({ index }) => index);

  if (enabledIndexes.length === 0) return null;
  if (key === 'Home') return enabledIndexes[0];
  if (key === 'End') return enabledIndexes[enabledIndexes.length - 1];

  const direction = key === 'ArrowRight' || key === 'ArrowDown' ? 1 : -1;
  const currentEnabledIndex = enabledIndexes.indexOf(currentIndex);
  if (currentEnabledIndex < 0) {
    return direction > 0
      ? enabledIndexes[0]
      : enabledIndexes[enabledIndexes.length - 1];
  }

  return enabledIndexes[
    (currentEnabledIndex + direction + enabledIndexes.length) % enabledIndexes.length
  ];
}

export function normalizeSwatchPickerOpacity(opacity: number | undefined): number {
  if (opacity === undefined || !Number.isFinite(opacity)) return 1;
  return Math.min(1, Math.max(0, opacity));
}
